def _topic_path():
    if not PROJECT_ID:
        raise RuntimeError("Missing PROJECT_ID (GCP_PROJECT/GOOGLE_CLOUD_PROJECT).")
    return _publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)


def _safe_b64decode(data):
    try:
        return base64.b64decode(data).decode("utf-8")
    except Exception:
        return None


def _download_blob_preview(bucket_name, object_name, generation=None, limit=DOWNLOAD_LIMIT_BYTES):
    bucket = _storage_client.bucket(bucket_name)
    blob = bucket.blob(object_name, generation=generation)
    data = blob.download_as_bytes(start=0, end=max(0, limit - 1)) if limit > 0 else b""
    return data


def _infer_content(data, content_type):
    text = None
